function DienstCard({ d, onClick }) {
  const Icon = d.icon;
  const [hover, setHover] = useState(false);
  return (
    <div onClick={onClick} onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)} style={{
      background:C.white, borderRadius:12, padding:28,
      border:`1px solid ${hover ? C.navyMid : C.border}`,
      cursor:"pointer", transition:"all 0.2s",
      boxShadow: hover ? "0 8px 28px rgba(27,58,107,0.12)" : "0 2px 8px rgba(27,58,107,0.05)",
      transform: hover ? "translateY(-3px)" : "none",
    }}>
      <div style={{ width:48, height:48, borderRadius:10, background:`${C.green}18`, display:"flex", alignItems:"center", justifyContent:"center", marginBottom:16 }}>
        <Icon size={22} color={C.green}/>
      </div>
      {d.badge && (
        <span style={{ display:"inline-block", padding:"3px 10px", background:`${C.green}18`, borderRadius:20, fontSize:11, color:C.green, fontWeight:700, marginBottom:10, fontFamily:FONT_H, letterSpacing:"0.04em" }}>Meest gevraagd</span>
      )}
      <h3 style={{ fontFamily:FONT_H, fontSize:18, fontWeight:700, color:C.navy, marginBottom:10 }}>{d.title}</h3>
      <p style={{ fontSize:14, color:C.gray, lineHeight:1.7, marginBottom:14, fontFamily:FONT_B }}>{d.desc}</p>
      <div style={{ display:"flex", flexWrap:"wrap" }}>{d.tags.map(t => <Tag key={t} label={t}/>)}</div>
    </div>
  );
}

function ProjectCard({ p }) {
  const [hover, setHover] = useState(false);
  const colors = { Warmtepomp:C.green, Airco:C.navyMid, Renovatie:C.navy, Nieuwbouw:C.navyMid, CV:C.navy };
  const col = colors[p.cat] || C.navy;
  return (
    <div onMouseEnter={() => setHover(true)} onMouseLeave={() => setHover(false)} style={{
      background:C.white, borderRadius:12, overflow:"hidden",
      border:`1px solid ${hover ? C.navyMid : C.border}`,
      boxShadow: hover ? "0 8px 24px rgba(27,58,107,0.12)" : "0 2px 8px rgba(27,58,107,0.05)",
      transform: hover ? "translateY(-3px)" : "none", transition:"all 0.2s",
    }}>
      <div style={{ height:140, background:`linear-gradient(135deg, ${C.navy} 0%, ${C.navyMid} 100%)`, display:"flex", alignItems:"center", justifyContent:"center" }}>
        <Wrench size={36} color="rgba(255,255,255,0.18)"/>
      </div>
      <div style={{ padding:22 }}>
        <span style={{ display:"inline-block", padding:"3px 10px", background:`${col}18`, borderRadius:20, fontSize:11, color:col, fontWeight:700, marginBottom:10, fontFamily:FONT_H }}>{p.cat}</span>
        <h3 style={{ fontFamily:FONT_H, fontSize:16, fontWeight:700, color:C.navy, marginBottom:8, lineHeight:1.3 }}>{p.title}</h3>
        <p style={{ fontSize:13, color:C.gray, lineHeight:1.65, fontFamily:FONT_B }}>{p.desc}</p>
      </div>
    </div>
  );
}

function FormField({ label, type="text", value, onChange, rows }) {
  return (
    <div style={{ marginBottom:18 }}>
      <label style={{ display:"block", fontSize:13, fontWeight:700, color:C.navy, marginBottom:6, fontFamily:FONT_H }}>{label}</label>
      {rows
        ? <textarea rows={rows} value={value} onChange={onChange} style={{ width:"100%", padding:"11px 13px", borderRadius:7, border:`1.5px solid ${C.border}`, fontFamily:FONT_B, fontSize:14, color:C.text, background:C.bg, outline:"none", resize:"vertical" }}/>
        : <input type={type} value={value} onChange={onChange} style={{ width:"100%", padding:"11px 13px", borderRadius:7, border:`1.5px solid ${C.border}`, fontFamily:FONT_B, fontSize:14, color:C.text, background:C.bg, outline:"none" }}/>
      }
    </div>
  );
}

/* ── Header ── */
function Header({ page, nav }) {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <header style={{
      position:"sticky", top:0, zIndex:100, width:"100%",
      background: scrolled ? C.navyDk : C.navyDk,
      borderBottom:`1px solid rgba(255,255,255,0.08)`,
      boxShadow: scrolled ? "0 2px 20px rgba(0,0,0,0.25)" : "none",
      transition:"box-shadow 0.3s",
    }}>
      <div style={{ width:"100%", maxWidth:1400, margin:"0 auto", padding:"0 32px", display:"flex", alignItems:"center", justifyContent:"space-between", height:76 }}>
        {/* Logo — mix-blend-mode:screen maakt de zwarte achtergrond transparant */}
        <button onClick={() => nav("home")} style={{ border:"none", background:"none", cursor:"pointer", padding:0, display:"flex", alignItems:"center" }}>
          <img src={LOGO} alt="Hartog-Bos Duurzame Installaties" style={{ height:52, objectFit:"contain", mixBlendMode:"screen" }}/>
        </button>

        {/* Nav */}
        <nav style={{ display:"flex", alignItems:"center", gap:4 }}>
          {NAV_LINKS.map(n => (
            <button key={n.id} onClick={() => nav(n.id)} style={{
              border:"none", borderBottom: page===n.id ? `2px solid ${C.green}` : "2px solid transparent",
              background:"none", cursor:"pointer", padding:"8px 14px", borderRadius:"6px 6px 0 0",
              fontFamily:FONT_H, fontSize:13, fontWeight:700,
              color: page===n.id ? C.white : "rgba(255,255,255,0.65)",
              letterSpacing:"0.03em", transition:"color 0.15s",
            }}
              onMouseEnter={e => e.currentTarget.style.color="white"}
              onMouseLeave={e => { if(page!==n.id) e.currentTarget.style.color="rgba(255,255,255,0.65)"; }}
            >{n.label}</button>
          ))}
        </nav>

        {/* Right */}
        <div style={{ display:"flex", alignItems:"center", gap:16 }}>
          <a href="tel:0612345678" style={{ display:"flex", alignItems:"center", gap:7, fontSize:13, fontWeight:700, color:"rgba(255,255,255,0.85)", textDecoration:"none", fontFamily:FONT_H }}>
            <Phone size={14} color={C.green}/> 06 12 34 56 78
          </a>
          <Btn onClick={() => nav("offerte")} variant="primary" small>Offerte aanvragen</Btn>
        </div>
      </div>
    </header>
  );
}

